namespace RecipeShare.Data;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = "";
    public string Category { get; set; } = "";
    public string Description { get; set; } = "";
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple, classic pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."]
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy Roman pasta with eggs, cheese, and pancetta.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = ["Cook spaghetti in salted water until al dente.", "Fry pancetta until crispy.", "Whisk eggs with grated Pecorino and pepper.", "Toss hot pasta with pancetta off heat.", "Add egg mixture and toss quickly to create a creamy sauce.", "Serve immediately with extra cheese."]
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or broil chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Simmer 10 minutes and serve with rice."]
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
            Description = "A tangy, sweet stir-fried noodle dish loaded with vegetables.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Garlic"],
            Steps = ["Soak rice noodles in warm water for 20 minutes.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry tofu and garlic in a hot wok.", "Add noodles and sauce, tossing to coat.", "Add bean sprouts and toss briefly.", "Serve with crushed peanuts and lime wedges."]
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa.", "Serve immediately."]
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh, creamy avocado dip with lime and cilantro.",
            Ingredients = ["Avocados", "Lime juice", "Cilantro", "Red onion", "Jalapeño", "Salt"],
            Steps = ["Halve avocados and remove pits.", "Mash avocado to desired consistency.", "Stir in lime juice, diced onion, cilantro, and jalapeño.", "Season with salt to taste.", "Serve with tortilla chips."]
        },
        new()
        {
            Id = 7, Title = "Miso Ramen", Category = "Asian",
            Description = "A warming bowl of miso-flavored ramen with toppings.",
            Ingredients = ["Ramen noodles", "Miso paste", "Chicken broth", "Soy sauce", "Soft-boiled egg", "Green onions", "Nori", "Sesame oil"],
            Steps = ["Bring chicken broth to a simmer.", "Whisk in miso paste and soy sauce.", "Cook ramen noodles according to package.", "Divide noodles into bowls and ladle broth over.", "Top with soft-boiled egg, green onions, and nori.", "Drizzle with sesame oil."]
        },
        new()
        {
            Id = 8, Title = "Palak Paneer", Category = "Indian",
            Description = "Cubes of paneer in a vibrant, spiced spinach sauce.",
            Ingredients = ["Paneer", "Spinach", "Onion", "Garlic", "Ginger", "Green chili", "Cream", "Cumin", "Garam masala"],
            Steps = ["Blanch spinach and blend into a smooth purée.", "Sauté cumin, onion, garlic, ginger, and chili.", "Add spinach purée and simmer.", "Stir in cream and garam masala.", "Add paneer cubes and cook 5 minutes.", "Serve with naan or rice."]
        },
    ];

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }
}

@rendermode InteractiveServer
@inject Data.RecipeService Recipes

<div class="star-rating d-inline-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => Rate(star)"
                title="Rate @star star(s)"
                disabled="@HasRated">
            @(star <= DisplayStars ? "★" : "☆")
        </button>
    }
    @if (HasRated)
    {
        <span class="text-success small">Thanks for rating!</span>
    }
    else if (TotalRatings > 0)
    {
        <span class="text-muted small">@AverageRating.ToString("0.0") (@TotalRatings ratings)</span>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private bool HasRated { get; set; }
    private int DisplayStars { get; set; }
    private double AverageRating { get; set; }
    private int TotalRatings { get; set; }

    protected override void OnParametersSet()
    {
        LoadRating();
    }

    private void Rate(int stars)
    {
        if (HasRated) return;
        Recipes.AddRating(RecipeId, stars);
        HasRated = true;
        DisplayStars = stars;
        LoadRating();
    }

    private void LoadRating()
    {
        var recipe = Recipes.GetById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
            if (!HasRated)
            {
                DisplayStars = (int)Math.Round(AverageRating);
            }
        }
    }
}

