@page "/"
@inject Data.RecipeService Recipes

<PageTitle>RecipeShare — Home</PageTitle>

<div class="text-center mb-4">
    <h1>🍽️ RecipeShare</h1>
    <p class="lead">Discover and share delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-4 g-4 mt-2">
    @foreach (var category in Recipes.GetCategories())
    {
        <div class="col">
            <a href="/category/@category" class="text-decoration-none">
                <div class="card h-100 shadow-sm">
                    <div class="card-body text-center">
                        <h3 class="card-title">@CategoryEmoji(category) @category</h3>
                        <p class="card-text text-muted">
                            @Recipes.GetByCategory(category).Count recipe(s)
                        </p>
                    </div>
                </div>
            </a>
        </div>
    }
</div>

@code {
    private static string CategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        _ => "🍴"
    };
}

