@page "/category/{CategoryName}"
@inject Data.RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                    </div>
                    <div class="card-footer">
                        <a href="/recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = "";

    private IReadOnlyList<Data.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = Recipes.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@inject Data.RecipeService Recipes

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <div class="mb-3">
        <strong>Rate this recipe:</strong>
        <StarRating RecipeId="recipe.Id" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h5>Steps</h5>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Data.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = Recipes.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject Data.RecipeService Recipes

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>Submit a Recipe</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@Model.Title</strong>" has been added.
        <a href="/recipe/@submittedId">View it here</a>.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
                <option value="">— Select —</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="Model.IngredientsText" class="form-control" rows="5" />
            <ValidationMessage For="() => Model.IngredientsText" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="Model.StepsText" class="form-control" rows="5" />
            <ValidationMessage For="() => Model.StepsText" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        var recipe = new Data.Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Description = $"A community-submitted {Model.Category} recipe.",
            Ingredients = Model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = Model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        Recipes.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }

    private void Reset()
    {
        Model = new();
        submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Add at least one ingredient.")]
        public string IngredientsText { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Add at least one step.")]
        public string StepsText { get; set; } = "";
    }
}

